t.script:

let isEditMode = false;
let originalFormData = {};

// Fields portal user can edit
const EDITABLE_FIELDS = [
  'employee_first_name','employee_middle_name','employee_last_name',
  'employee_name_arabic','private_email','private_phone','private_street',
  'private_street2','private_city','private_zip','emergency_contact',
  'emergency_phone','x_emirates_id','x_emirates_expiry','x_passport_number',
  'x_passport_country','x_passport_issue','x_passport_expiry','whatsapp',
  'linkedin','facebook_profile','insta_profile','twitter_profile',
  'house_no','area_name','zip_code','birthday','place_of_birth',
  'emergency_contact_person_name','emergency_contact_person_phone',
  'emergency_contact_person_name_1','emergency_contact_person_phone_1',
  'home_land_line_no','country_code_for_personal_mob_no',
  'emirates_id_number','emirates_issue_date','emirates_expiry_date',
  'issue_date','aadhar_no','pan','blooad_group','religion',
  'employee_nominee_name','employee_nominee_contact_no',
  'spouse_support_no','spouse_passport_issue_date','spouse_passport_expiry_date',
  'spouse_visa_no','spouse_visa_expire_date','spouse_emirates_id_no',
  'spouse_emirates_issue_date','spouse_emirates_id_expiry_date',
  'spouse_aadhar_no','dependent_child_name_1','dependent_child_dob_1',
  'dependent_child_passport_no','dependent_child_visa_no_1',
  'dependent_child_aadhar_no_1','u_private_street','e_private_street',
];

function toggleEditMode() {
  document.getElementById('editMode').checked ? enableEditMode() : disableEditMode();
}

function enableEditMode() {
  isEditMode = true;
  document.getElementById('editMode').checked = true;
  storeOriginalFormData();
  EDITABLE_FIELDS.forEach(name => {
    document.querySelectorAll('[name="' + name + '"]').forEach(el => {
      el.removeAttribute('readonly');
      el.removeAttribute('disabled');
    });
  });
  document.querySelectorAll('input[type="file"]').forEach(el => el.removeAttribute('disabled'));
  document.getElementById('formActions').style.display = 'block';
  document.getElementById('viewActions').style.display = 'none';
  document.querySelectorAll('#personalDetailsForm [data-validation]').forEach(input => {
    input.addEventListener('input', validateField);
    input.addEventListener('blur', validateField);
  });
}

function disableEditMode() {
  isEditMode = false;
  document.getElementById('editMode').checked = false;
  document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select, #personalDetailsForm textarea').forEach(input => {
    if (input.type !== 'hidden') {
      input.setAttribute('readonly', 'readonly');
      if (input.tagName === 'SELECT' || input.type === 'file') input.setAttribute('disabled', 'disabled');
    }
  });
  document.getElementById('formActions').style.display = 'none';
  document.getElementById('viewActions').style.display = 'block';
  clearValidationStates();
}

function storeOriginalFormData() {
  const formData = new FormData(document.getElementById('personalDetailsForm'));
  originalFormData = {};
  for (let [key, value] of formData.entries()) originalFormData[key] = value;
}

function cancelEdit() {
  for (let [key, value] of Object.entries(originalFormData)) {
    const input = document.querySelector('[name="' + key + '"]');
    if (input) input.value = value;
  }
  disableEditMode();
  showMessage('Changes cancelled.', 'info');
}

function saveAsDraft() {
  const formData = new FormData(document.getElementById('personalDetailsForm'));
  const draftData = {};
  for (let [key, value] of formData.entries()) draftData[key] = value;
  localStorage.setItem('profileDraft_personal', JSON.stringify(draftData));
  showMessage('Profile saved as draft.', 'info');
}

function validateField(event) {
  const field = event.target;
  const type = field.getAttribute('data-validation');
  let isValid = true, errorMessage = '';
  field.classList.remove('is-valid', 'is-invalid');
  if (type) {
    if (type === 'email' && field.value && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(field.value)) {
      isValid = false; errorMessage = 'Please enter a valid email address.';
    } else if (type === 'phone' && field.value && !/^[+]?[0-9\s\-\(\)]+$/.test(field.value)) {
      isValid = false; errorMessage = 'Please enter a valid phone number.';
    } else if (type === 'required' && (!field.value || !field.value.trim())) {
      isValid = false; errorMessage = 'This field is required.';
    } else if (type === 'date' && field.value && isNaN(new Date(field.value).getTime())) {
      isValid = false; errorMessage = 'Please enter a valid date.';
    } else if (type === 'future-date' && field.value && new Date(field.value) <= new Date()) {
      isValid = false; errorMessage = 'Date must be in the future.';
    }
  }
  if (field.value) {
    field.classList.add(isValid ? 'is-valid' : 'is-invalid');
    if (!isValid) {
      const fb = field.parentNode.querySelector('.invalid-feedback');
      if (fb) fb.textContent = errorMessage;
    }
  }
  return isValid;
}

function clearValidationStates() {
  document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(i => i.classList.remove('is-valid','is-invalid'));
}

document.getElementById('personalDetailsForm').addEventListener('submit', function(e) {
  e.preventDefault();
  let isFormValid = true;
  document.querySelectorAll('#personalDetailsForm [data-validation]').forEach(input => {
    if (!validateField({target: input})) isFormValid = false;
  });
  if (!isFormValid) { showMessage('Please correct errors before submitting.', 'error'); return; }
  fetch('/my/employee/personal', { method: 'POST', body: new FormData(this) })
    .then(r => r.json())
    .then(data => {
      if (data.success) {
        showMessage('Profile updated successfully!', 'success');
        disableEditMode();
        localStorage.removeItem('profileDraft_personal');
      } else {
        showMessage('Error: ' + (data.error || 'Unknown error'), 'error');
      }
    })
    .catch(() => showMessage('Network error. Please try again.', 'error'));
});

function showMessage(text, type) {
  const c = document.getElementById('messageContainer');
  const s = document.getElementById('successMessage');
  const er = document.getElementById('errorMessage');
  s.style.display = 'none'; er.style.display = 'none';
  s.classList.remove('show'); er.classList.remove('show');
  if (type === 'success') { document.getElementById('successText').textContent = text; s.style.display = 'block'; s.classList.add('show'); }
  else { document.getElementById('errorText').textContent = text; er.style.display = 'block'; er.classList.add('show'); }
  c.style.display = 'block';
  c.scrollIntoView({behavior:'smooth'});
  setTimeout(() => { s.classList.remove('show'); er.classList.remove('show'); }, 5000);
}

document.addEventListener('DOMContentLoaded', function() {
  const draft = localStorage.getItem('profileDraft_personal');
  if (draft) {
    try {
      Object.entries(JSON.parse(draft)).forEach(([key, value]) => {
        const input = document.querySelector('[name="' + key + '"]');
        if (input && input.type !== 'hidden') input.value = value;
      });
      showMessage('Draft loaded. Continue editing or cancel to discard.', 'info');
    } catch(e) {}
  }
});
